<div class="card form-card-narrow"><h3>Bill Payment</h3><form method="post" action="<?= base_url('index.php?route=wallet/bill-payment/submit') ?>"><input type="hidden" name="_csrf" value="<?= csrf_token() ?>"><div class="form-group"><label>Bill Category</label><select name="bill_category_id" required><option value="">Select category</option><?php foreach ($categories as $category): ?><option value="<?= (int)$category['id'] ?>"><?= e($category['name']) ?></option><?php endforeach; ?></select></div><div class="form-group"><label>Account / Consumer Number</label><input type="text" name="account_number" required></div><div class="form-group"><label>Amount</label><input type="number" step="0.01" min="1" name="amount" required></div><button class="btn btn-primary" type="submit">Pay Bill</button></form></div>
